function W($p,$c){$d=Split-Path -Parent $p;if($d -and -not(Test-Path $d)){New-Item -ItemType Directory -Path $d -Force|Out-Null};[IO.File]::WriteAllText($p,$c,[Text.UTF8Encoding]::new($false))}
